const item = $input.item.json;
const stripHtml = (html) => {
  if (!html) return '';
  return html
    .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, ' ')
    .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, ' ')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&nbsp;/g, ' ').replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<').replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"').replace(/&#39;/g, "'")
    .replace(/\s+/g, ' ').trim();
};
const bodyClean = stripHtml(item.body?.content || item.bodyPreview || '');
return {
  json: {
    email_id:        item.id || '',
    received_date:   item.receivedDateTime || '',
    from_address:    item.from?.emailAddress?.address || '',
    from_name:       item.from?.emailAddress?.name || '',
    to_address:      item.toRecipients?.[0]?.emailAddress?.address || '',
    subject:         item.subject || '',
    body_preview:    bodyClean.substring(0, 500),
    body_full:       bodyClean.substring(0, 3000),
    has_attachments: item.hasAttachments ? 'yes' : 'no',
    importance:      item.importance || 'normal',
    conversation_id: item.conversationId || ''
  }
};

// FIX: Reference Fetch Sent Reply node directly so we have the full list,
// not just the current pipeline item (which is what $input.all() gives in per-item mode)
const sentItems = $('Fetch Sent Reply').all();
const incomingEmail = $input.item.json;
const targetConvId = incomingEmail.conversation_id;

const stripHtml = (html) => {
  if (!html) return '';
  return html
    .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, ' ')
    .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, ' ')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&nbsp;/g, ' ').replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<').replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"').replace(/&#39;/g, "'")
    .replace(/\s+/g, ' ').trim();
};

const stripQuotedAndSig = (text) => {
  const cutoffs = [
    /\nFrom:.*Sent:/s,
    /\n-----Original Message-----/,
    /\nOn .* wrote:/,
    /\n_{3,}/
  ];
  let result = text;
  for (const pattern of cutoffs) {
    const match = result.search(pattern);
    if (match > 10) { result = result.substring(0, match).trim(); break; }
  }
  return result
    .replace(/Sent from my T-Mobile[\s\S]*$/i, '')
    .replace(/Get Outlook for[\s\S]*$/i, '')
    .replace(/He is no fool[\s\S]*$/i, '')
    .replace(/Try our online[\s\S]*$/i, '')
    .trim();
};

// Match sent reply by conversationId
const match = sentItems.find(item =>
  item.json.conversationId === targetConvId
);

const keithReplyText = match
  ? stripQuotedAndSig(stripHtml(match.json.body?.content || match.json.bodyPreview || '')).substring(0, 2000)
  : '';

return {
  json: {
    ...incomingEmail,
    keith_reply_found: match ? 'YES' : 'NO',
    keith_reply_text: keithReplyText,
    keith_reply_date: match ? (match.json.sentDateTime || '') : ''
  }
};

