const ai = $json.output || {};
const email = $('Extract {{OWNER_FIRST_NAME}} Reply').item.json;
const safe = (v) => {
  if (v === null || v === undefined) return '';
  if (typeof v === 'boolean') return v ? 'TRUE' : 'FALSE';
  if (typeof v === 'number') return String(v);
  return String(v).replace(/\r\n/g, '\n').substring(0, 5000);
};
return {
  json: {
    email_id:               safe(email.email_id),
    received_date:          safe(email.received_date),
    from_address:           safe(email.from_address),
    from_name:              safe(email.from_name),
    to_address:             safe(email.to_address),
    subject:                safe(email.subject),
    body_preview:           safe(email.body_preview),
    has_attachments:        safe(email.has_attachments),
    keith_reply_found:      safe(email.keith_reply_found),
    keith_actual_reply:     safe(email.keith_reply_text),
    keith_reply_date:       safe(email.keith_reply_date),
    category:               safe(ai.category),
    priority:               safe(ai.priority),
    routing_label:          safe(ai.routing_label),
    is_real_person:         safe(ai.is_real_person),
    spam_confidence:        safe(ai.spam_confidence),
    requires_keith:         safe(ai.requires_keith_decision),
    sensitivity_flag:       safe(ai.sensitivity_flag),
    flag_reason:            safe(ai.flag_reason),
    summary:                safe(ai.summary),
    recommended_action:     safe(ai.recommended_action),
    ai_draft_reply:         safe(ai.draft_reply),
    confidence_score:       safe(ai.confidence_score),
    relationship_type:      safe(ai.relationship_type),
    topic_tags:             safe(ai.topic_tags),
    reply_needed:           safe(ai.reply_needed),
    draft_notes:            safe(ai.draft_notes),
    keith_category_correct: '',
    keith_draft_rating:     '',
    keith_notes:            '',
    reviewed:               'NO'
  }
};
